#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,Mod=998244353;inline void DN(int &x){x>=Mod?x-=Mod:0;}
int head[N],des[N<<1],nxt[N<<1],cgt=1,n,m,ans=1,m2;bool del[N],isc[N];int deg[N];
int dfn[N],low[N],stk[N<<1],top,cdt,dep[N],inv[N],tot,len[N],cid; vector<int> dcc[N];
inline void Init(int n){inv[0]=inv[1]=1;rep(2,n,i)inv[i]=1ll*(Mod-Mod/i)*inv[Mod%i]%Mod;}
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
template<typename T> inline void Clear(vector<T> &x){vector<T> t;x.swap(t);}
inline void dfs(int u=1,int f=0)
{
	dfn[stk[++top]=u]=low[u]=++cdt;
	grep(u,i)if(!del[i>>1]&&i!=f)
	{
		int v=des[i]; if(!dfn[v])
		{
			stk[++top]=~i;dep[v]=dep[u]+1;
			dfs(v,i^1);low[u]=min(low[u],low[v]);
			if(dfn[u]<=low[v])
			{
				if(dfn[u]==low[v])
				{
					Clear(dcc[++tot]);dcc[tot].push_back(u);
					int tmp=0,cet=0; do
					{
						tmp=stk[top--];
						if(tmp>0)
						{
							dcc[tot].push_back(tmp);
							if(deg[tmp]>2)len[tot]=dep[tmp]-dep[u];
						}
						else ++cet;
					}while(tmp!=(~i));
					if(cet>int(dcc[tot].size()))cid=tot;
				}
				else top-=2;
			}
		}
		else if(dfn[u]>dfn[v]) {stk[++top]=~i;low[u]=min(low[u],dfn[v]);}
	}
	
}
int main()
{
	n=read();m=read();Init(n);
	rep(1,m,i)ins(read(),read());dfs();
	rep(1,tot,i)if(i!=cid)ans=1ll*ans*dcc[i].size()%Mod;
	if(!cid)return printf("%d\n",ans),0;
	for(int v:dcc[cid])isc[v]=true;
	memset(head+1,0,n*sizeof(int));cgt=1;
	rep(1,m,i)
	{
		int u=des[i<<1],v=des[i<<1|1];
		if(isc[u]&&isc[v]){++m2;++deg[u];++deg[v];ins(u,v);}
	}
	vector<int> qwq=dcc[cid];
	for(int u:qwq)
	{
		if(deg[u]==3)grep(u,i)
		{
			del[i>>1]=true;
			memset(dfn+1,0,n*sizeof(int));dep[u]=0;
			cdt=tot=cid=top=0;dfs(u);
			if(cid){del[i>>1]=false;continue;}
			int sum=0,cnt=0,P=1;
			rep(1,tot,i)
			{
				const int s=dcc[i].size(); P=1ll*P*s%Mod;cnt+=s;
				sum=(1ll*len[i]*(s-len[i])%Mod*inv[s]+sum)%Mod;
//				printf("%d :: %d %d %d\n",i,len[i],s,inv[s]);
			}
//			printf("%d %d %d %d %d\n",sum,m2,cnt,P,ans);
			printf("%lld\n",1ll*(sum+m2-cnt)*P%Mod*ans%Mod);return 0;
		}
	}
}
